SELECT action, description
FROM experiment_logs
WHERE log_id = 0;

SELECT organization_name
FROM organizations
WHERE organization_id = 0;

SELECT COUNT(experiment_user_id) AS experiment_count
FROM experiment_users
WHERE user_id = 1;

SELECT permission
FROM access_control
WHERE role_id = 1;

